// ==========================================================================
// GLOBAL FUNCTIONS (Accessible by inline HTML onclick/onload attributes)
// ==========================================================================

window.downloadVCard = function (event) {
    // Prevent the anchor link from jumping to the top of the page
    event.preventDefault();

    // Construct the vCard data
    const vcardData = `BEGIN:VCARD
VERSION:3.0
FN:Integrative Dentistry
ORG:Integrative Dentistry
TEL;TYPE=WORK,VOICE:206-367-6453
EMAIL;TYPE=WORK,INTERNET:info@integrativedentistry.com
URL:http://integrativedentistry.com
ADR;TYPE=WORK:;;9730 3rd Ave NE\, Suite 205;Seattle;WA;98115;United States
PHOTO;ENCODING=b;TYPE=PNG:

END:VCARD`;

    // Create a blob from the text data
    const blob = new Blob([vcardData], { type: 'text/vcard' });
    const url = window.URL.createObjectURL(blob);

    // Create a temporary anchor element to trigger the download
    const a = document.createElement('a');
    a.style.display = 'none';
    a.href = url;
    a.download = 'Integrative_Dentistry.vcf';

    // Append to DOM, click to download, and cleanup
    document.body.appendChild(a);
    a.click();

    // Slight delay for iOS compatibility before revoking the URL
    setTimeout(() => {
        window.URL.revokeObjectURL(url);
        document.body.removeChild(a);
    }, 100);
};

// Start or Pause Font Awesome Icons
window.initializeIconPauses = function () {
    const animatedIcons = document.querySelectorAll('.fa-bounce, .fa-spin, .fa-pulse, .fa-beat, .fa-fade, .fa-beat-fade, .fa-bounce, .fa-flip, .fa-flip-360, .fa-shake, .fa-spin-pulse, .fa-spin-snap, .fa-spin-snap-4, .fa-spin-snap-8, .fa-spin, .fa-spin-reverse, .fa-float, .fa-wag, .fa-buzz, .fa-swing, .fa-jello');

    animatedIcons.forEach(icon => {
        if (icon.dataset.pauseInitialized) return;

        icon.dataset.pauseInitialized = "true";

        icon.addEventListener('animationiteration', () => {
            icon.style.animationPlayState = 'paused';
            setTimeout(() => {
                icon.style.animationPlayState = 'running';
            }, 3000);
        });
    });
};

// ==========================================================================
// MASTER INITIALIZATION: Ensures all HTML is loaded before binding actions
// ==========================================================================
document.addEventListener('DOMContentLoaded', () => {

    // 1. Initialize Global Features
    window.initializeIconPauses();

    // ==========================================================================
    // 2. ACCESSIBILITY STATE MANAGEMENT ENGINE
    // ==========================================================================
    const settings = {
        'adhd-mode': { class: 'adhd-mode', element: document.documentElement, btnId: 'btn-adhd-mode' },
        'dyslexia-font': { class: 'dyslexia-enabled', element: document.body, btnId: 'btn-dyslexia-font' },
        'large-cursor': { class: 'large-cursor', element: document.documentElement, btnId: 'btn-large-cursor' },
        'dark-mode': { class: 'dark-theme', element: document.body, btnId: 'theme-btn' },
        'high-contrast': { class: 'high-contrast', element: document.documentElement, btnId: 'btn-high-contrast' }
    };

    // Load and Apply saved settings
    Object.keys(settings).forEach(key => {
        if (localStorage.getItem(key) === 'enabled') {
            const { class: className, element, btnId } = settings[key];
            element.classList.add(className);

            const btn = document.getElementById(btnId);
            if (btn) btn.classList.add('active');
        }
    });

    // Toggle Function (Bound to Window for dynamic button bindings)
    window.toggleAccessibility = function (key) {
        const { class: className, element, btnId } = settings[key];
        const isActive = element.classList.toggle(className);

        localStorage.setItem(key, isActive ? 'enabled' : 'disabled');

        const btn = document.getElementById(btnId);
        if (btn) btn.classList.toggle('active', isActive);
    };

    // Dark Mode Button Binding
    const themeBtn = document.getElementById('theme-btn');
    if (themeBtn) {
        themeBtn.addEventListener('click', () => {
            window.toggleAccessibility('dark-mode');
        });
    }

    // Access Menu Overlay Toggle
    const accessBtn = document.getElementById('access-btn');
    const accessMenu = document.getElementById('access-menu');
    if (accessBtn && accessMenu) {
        accessBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            accessMenu.classList.toggle('hidden');
        });

        document.addEventListener('click', (e) => {
            if (!accessMenu.contains(e.target) && e.target !== accessBtn) {
                accessMenu.classList.add('hidden');
            }
        });
    }

    // ADHD Mask Dynamic Injection and Tracking
    if (!document.getElementById('adhd-mask')) {
        const mask = document.createElement('div');
        mask.id = 'adhd-mask';
        document.body.appendChild(mask);
    }
    document.addEventListener('mousemove', (e) => {
        if (document.documentElement.classList.contains('adhd-mode')) {
            document.documentElement.style.setProperty('--mouse-y', `${e.clientY}px`);
        }
    });

    // ==========================================================================
    // 3. FLUID SCROLL, HEADER, & REVEAL OBSERVERS
    // ==========================================================================

    // Header Shrink Scroll Tracker
    const mainHeader = document.querySelector('header');
    if (mainHeader) {
        window.addEventListener('scroll', () => {
            if (window.scrollY > 80) {
                mainHeader.classList.add('scrolled');
            } else {
                mainHeader.classList.remove('scrolled');
            }
        }, { passive: true });
    }

    // Smooth-Scroll Reveal Engine
    const revealSettings = {
        threshold: 0.05,
        rootMargin: "0px 0px -40px 0px"
    };

    const sectionObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add('visible');
            }
        });
    }, revealSettings);

    document.querySelectorAll('.scroll-animate').forEach(section => {
        sectionObserver.observe(section);
    });

    // ==========================================================================
    // 4. NAVIGATION, DRAWERS, & MENUS
    // ==========================================================================

    // Isomorphic Mobile Menu Logic
    const mobileToggle = document.querySelector('.mobile-nav-toggle');
    const navLinks = document.querySelectorAll('.nav-links a.nav-item');

    if (mobileToggle) {
        const toggleMenu = (e) => {
            e.stopPropagation();
            e.preventDefault();
            const isMenuOpen = document.body.getAttribute('data-nav-open') === 'true';
            document.body.setAttribute('data-nav-open', !isMenuOpen);
            mobileToggle.setAttribute('aria-expanded', !isMenuOpen);
        };

        mobileToggle.addEventListener('click', toggleMenu);

        navLinks.forEach(link => {
            link.addEventListener('click', () => {
                if (!link.parentElement.classList.contains('dropdown')) {
                    document.body.setAttribute('data-nav-open', 'false');
                    mobileToggle.setAttribute('aria-expanded', 'false');
                }
            });
        });

        document.addEventListener('click', (e) => {
            if (document.body.getAttribute('data-nav-open') === 'true') {
                const navContainer = document.querySelector('nav');
                if (navContainer && !navContainer.contains(e.target)) {
                    document.body.setAttribute('data-nav-open', 'false');
                    mobileToggle.setAttribute('aria-expanded', 'false');
                }
            }
        });
    }

    // Unified Mobile Contact Hub Overlay
    const hubTrigger = document.querySelector('.contact-hub-trigger');
    const hubMenuItems = document.querySelectorAll('.hub-menu-item');

    if (hubTrigger) {
        const toggleHub = (e) => {
            e.stopPropagation();
            e.preventDefault();
            const isOpen = document.body.getAttribute('data-contact-open') === 'true';
            document.body.setAttribute('data-contact-open', !isOpen);
            hubTrigger.setAttribute('aria-expanded', !isOpen);
        };

        hubTrigger.addEventListener('click', toggleHub);
        hubTrigger.addEventListener('touchstart', toggleHub, { passive: false });

        hubMenuItems.forEach(item => {
            item.addEventListener('click', () => {
                document.body.setAttribute('data-contact-open', 'false');
                hubTrigger.setAttribute('aria-expanded', 'false');
            });
        });

        document.addEventListener('click', (e) => {
            if (document.body.getAttribute('data-contact-open') === 'true') {
                const hubContainer = document.querySelector('.mobile-contact-hub');
                if (hubContainer && !hubContainer.contains(e.target)) {
                    document.body.setAttribute('data-contact-open', 'false');
                    hubTrigger.setAttribute('aria-expanded', 'false');
                }
            }
        });
    }

    // ==========================================================================
    // 5. INTERACTIVE DYNAMIC CONTENT & LISTENERS
    // ==========================================================================

    // Hover Tooltip Tracker Matrix (Text Bounds)
    const tooltipCanvas = document.getElementById('cursor-tooltip');
    const pointerOffset = { x: 15, y: 15 };

    if (window.matchMedia('(hover: hover)').matches) {
        document.querySelectorAll('[data-tooltip]').forEach(targetElement => {
            targetElement.addEventListener('mouseenter', (event) => {
                if (tooltipCanvas) {
                    document.querySelectorAll('[data-tooltip]').forEach(targetElement => {
                        targetElement.addEventListener('mouseenter', (event) => {
                            const blurbText = event.currentTarget.getAttribute('data-tooltip');
                            if (blurbText) {
                                tooltipCanvas.textContent = blurbText;
                                tooltipCanvas.classList.add('visible');
                            }
                        });

                        targetElement.addEventListener('mousemove', (event) => {
                            const tooltipWidth = tooltipCanvas.offsetWidth;
                            const tooltipHeight = tooltipCanvas.offsetHeight;
                            let targetX = event.clientX + pointerOffset.x;
                            let targetY = event.clientY + pointerOffset.y;

                            if (targetX + tooltipWidth > window.innerWidth) {
                                targetX = event.clientX - tooltipWidth - pointerOffset.x;
                            }
                            if (targetY + tooltipHeight > window.innerHeight) {
                                targetY = event.clientY - tooltipHeight - pointerOffset.y;
                            }
                            tooltipCanvas.style.left = `${targetX}px`;
                            tooltipCanvas.style.top = `${targetY}px`;
                        });

                        targetElement.addEventListener('mouseleave', () => {
                            tooltipCanvas.classList.remove('visible');
                        });
                    });
                }

                // Dynamic Floating Image Tooltip Engine
                const imageTooltipCanvas = document.getElementById('image-hover-tooltip');
                const imageTooltipImg = document.getElementById('hover-tooltip-img');

                if (imageTooltipCanvas && imageTooltipImg) {
                    document.querySelectorAll('.js-image-tooltip-trigger').forEach(target => {
                        target.addEventListener('mouseenter', (e) => {
                            const imgSrc = e.currentTarget.getAttribute('data-image-src');
                            if (imgSrc) {
                                imageTooltipImg.src = imgSrc;
                                imageTooltipCanvas.classList.add('visible');
                            }
                        });

                        target.addEventListener('mousemove', (e) => {
                            const tooltipWidth = imageTooltipCanvas.offsetWidth;
                            const tooltipHeight = imageTooltipCanvas.offsetHeight || 180;

                            let targetX = e.clientX + 20;
                            let targetY = e.clientY - tooltipHeight - 20;

                            if (targetX + tooltipWidth > window.innerWidth) {
                                targetX = e.clientX - tooltipWidth - 20;
                            }
                            if (targetY < 0) {
                                targetY = e.clientY + 20;
                            }

                            imageTooltipCanvas.style.left = `${targetX}px`;
                            imageTooltipCanvas.style.top = `${targetY}px`;
                        });

                        target.addEventListener('mouseleave', () => {
                            imageTooltipCanvas.classList.remove('visible');
                        });
                    });
                }
            });
        });
    }

    // 3D Magnetic Social Icon Evasion Engine
    document.querySelectorAll('.social-circle-btn').forEach(button => {
        const icon = button.querySelector('i');
        if (!icon) return;

        button.addEventListener('mousemove', (e) => {
            const rect = button.getBoundingClientRect();
            const centerX = rect.left + rect.width / 2;
            const centerY = rect.top + rect.height / 2;
            const mouseX = e.clientX - centerX;
            const mouseY = e.clientY - centerY;

            const pushX = -(mouseX * 0.35);
            const pushY = -(mouseY * 0.35);

            icon.style.transform = `translate(${pushX}px, ${pushY}px) scale(2.5)`;
        });

        button.addEventListener('mouseleave', () => {
            icon.style.transform = 'translate(0px, 0px) scale(1)';
        });
    });

    // Flow IV Speech Bubble Timer
    setTimeout(() => {
        const speechBubble = document.getElementById('flow-iv-speech');
        if (speechBubble) {
            speechBubble.classList.add('show');

            setTimeout(() => {
                speechBubble.classList.remove('show');
            }, 30000); // 30 second dismiss
        }
    }, 5000);

    // Phone Number Auto-Formatter
    const phoneInput = document.getElementById('intake-phone');
    if (phoneInput) {
        phoneInput.addEventListener('input', function (e) {
            let cleaned = e.target.value.replace(/\D/g, '');
            cleaned = cleaned.substring(0, 10);

            let formatted = '';
            if (cleaned.length > 0) {
                formatted = '(' + cleaned.substring(0, 3);
            }
            if (cleaned.length >= 4) {
                formatted += ') ' + cleaned.substring(3, 6);
            }
            if (cleaned.length >= 7) {
                formatted += '-' + cleaned.substring(6, 10);
            }
            e.target.value = formatted;
        });
    }

    // ==========================================================================
    // 6. COMPONENT SWITCHERS (Bento, Wellness, Bio Matrix)
    // ==========================================================================

    // Wellness Ecosystem Switcher
    const serviceItems = document.querySelectorAll('.service-nav-item');
    const serviceCards = document.querySelectorAll('.service-display-card');

    if (serviceItems.length > 0 && serviceCards.length > 0) {
        const handleServiceSwitch = (item) => {
            if (item.classList.contains('active')) return;
            serviceItems.forEach(nav => nav.classList.remove('active'));
            item.classList.add('active');

            const targetID = item.getAttribute('data-service-target');
            serviceCards.forEach(card => {
                card.classList.remove('active');
                if (card.id === `service-${targetID}`) {
                    card.classList.add('active');
                    const scrollArea = card.querySelector('.content-scroll-area');
                    if (scrollArea) scrollArea.scrollTop = 0;
                }
            });
        };

        serviceItems.forEach(item => {
            item.addEventListener('mouseenter', () => handleServiceSwitch(item));
            item.addEventListener('click', () => handleServiceSwitch(item));
        });
    }

    // Holistic Provider Profile Matrix Switcher
    const teamCards = document.querySelectorAll('.provider-avatar-card');
    const bioCards = document.querySelectorAll('.team-display-card');

    if (teamCards.length > 0 && bioCards.length > 0) {
        teamCards.forEach(card => {
            card.addEventListener('click', () => {
                if (card.classList.contains('active')) return;
                teamCards.forEach(item => item.classList.remove('active'));
                card.classList.add('active');

                const targetID = card.getAttribute('data-team-target');
                bioCards.forEach(bio => {
                    bio.classList.remove('active');
                    if (bio.id === `team-${targetID}`) {
                        bio.classList.add('active');
                    }
                });
            });
        });
    }

    // Interactive Biological FAQ Accordion & Search
    const faqTriggers = document.querySelectorAll('.faq-trigger');
    const filterPills = document.querySelectorAll('.filter-pill');
    const faqCards = document.querySelectorAll('.faq-wrapper-card');
    const searchInput = document.getElementById('faq-search-input');

    if (faqCards.length > 0) {
        const applyFilters = () => {
            const activePill = document.querySelector('.filter-pill.active');
            const filterTarget = activePill ? activePill.getAttribute('data-faq-filter') : 'all';
            const searchTerm = searchInput ? searchInput.value.toLowerCase().trim() : '';

            faqCards.forEach(card => {
                const cardCategory = card.getAttribute('data-faq-category');
                const questionText = card.querySelector('.faq-question-text').textContent.toLowerCase();
                const answerText = card.querySelector('.faq-panel-content').textContent.toLowerCase();

                const matchesCategory = (filterTarget === 'all' || cardCategory === filterTarget);
                const matchesSearch = (questionText.includes(searchTerm) || answerText.includes(searchTerm));

                if (!(matchesCategory && matchesSearch) && card.classList.contains('open')) {
                    card.classList.remove('open');
                    const panel = card.querySelector('.faq-response-panel');
                    if (panel) panel.style.maxHeight = null;
                    const trigger = card.querySelector('.faq-trigger');
                    if (trigger) trigger.setAttribute('aria-expanded', 'false');
                }

                if (matchesCategory && matchesSearch) {
                    card.classList.remove('hidden');
                } else {
                    card.classList.add('hidden');
                }
            });
        };

        filterPills.forEach(pill => {
            pill.addEventListener('click', () => {
                const grid = pill.closest('.faq-filter-grid');

                if (window.innerWidth <= 1024) {
                    if (!grid.classList.contains('dropdown-open') && pill.classList.contains('active')) {
                        grid.classList.add('dropdown-open');
                    } else {
                        grid.classList.remove('dropdown-open');
                    }
                }

                if (pill.classList.contains('active')) return;
                filterPills.forEach(item => item.classList.remove('active'));
                pill.classList.add('active');
                applyFilters();
            });
        });

        if (searchInput) searchInput.addEventListener('input', applyFilters);

        faqTriggers.forEach(trigger => {
            trigger.addEventListener('click', () => {
                const wrapper = trigger.closest('.faq-wrapper-card');
                const panel = wrapper.querySelector('.faq-response-panel');
                const isOpen = wrapper.classList.contains('open');

                document.querySelectorAll('.faq-wrapper-card.open').forEach(openCard => {
                    if (openCard !== wrapper) {
                        openCard.classList.remove('open');
                        openCard.querySelector('.faq-response-panel').style.maxHeight = null;
                        openCard.querySelector('.faq-trigger').setAttribute('aria-expanded', 'false');
                    }
                });

                if (isOpen) {
                    wrapper.classList.remove('open');
                    panel.style.maxHeight = null;
                    trigger.setAttribute('aria-expanded', 'false');
                } else {
                    wrapper.classList.add('open');
                    panel.style.maxHeight = panel.scrollHeight + "px";
                    trigger.setAttribute('aria-expanded', 'true');
                }
            });
        });
    }

    // Off-Canvas Bento Drawer Engine & Library
    const bentoCards = document.querySelectorAll('.bento-card');
    const drawer = document.getElementById('service-drawer');
    const overlay = document.getElementById('drawer-overlay');
    const closeBtn = document.getElementById('close-drawer-btn');
    const drawerTitle = document.getElementById('drawer-title');
    const drawerIcon = document.getElementById('drawer-icon');
    const drawerIntro = document.getElementById('drawer-intro');
    const drawerList = document.getElementById('drawer-list');

    const serviceData = {
        biocompatible: {
            title: "Biocompatible Restorations",
            icon: '<i class="fa-solid fa-seedling"></i>',
            intro: "We exclusively utilize premium, non-reactive materials to ensure your dental restorations exist in perfect harmony with your immune system.",
            services: [
                { name: "BPA-Free Composite Fillings", desc: "Tooth-colored structural resins completely devoid of Bisphenol A, offering a natural and durable fix." },
                { name: "Ceramic Crowns & Inlays", desc: "High-strength, metal-free zirconium and porcelain caps tailored via CAD/CAM for a precise, biocompatible fit." },
                { name: "Fluoride-Free Treatments", desc: "Alternative natural remineralization protocols avoiding systemic fluoride exposure." }
            ]
        },
        smart: {
            title: "SMART Protocol",
            icon: '<i class="fa-solid fa-shield-halved"></i>',
            intro: "Our rigorous containment protocol prevents toxic elemental mercury exposure when replacing legacy silver-amalgam fillings.",
            services: [
                { name: "Advanced Air Filtration", desc: "High-volume aerosol vacuums and specialized room purifiers strictly isolate the treatment zone." },
                { name: "Alternative Oxygen Supply", desc: "Nasal hoods deliver clean oxygen, completely bypassing ambient vapors during extraction." },
                { name: "Non-Latex Dental Dams", desc: "A customized physical barrier preventing the swallowing or absorption of amalgam particulate." }
            ]
        },
        ozone: {
            title: "Ozone Therapy",
            icon: '<i class="fa-solid fa-bolt"></i>',
            intro: "Harnessing the power of pure bio-oxidative gas (O3) to eliminate pathogens and accelerate cellular healing, entirely naturally.",
            services: [
                { name: "Cavity Arrest", desc: "Painless application of ozone gas to sterilize micro-decay before it requires drilling." },
                { name: "Root Canal Disinfection", desc: "Bathing deep dental canals in ozonated water to eradicate persistent anaerobic bacteria." },
                { name: "Surgical Healing Acceleration", desc: "Post-extraction ozone treatments to stimulate blood flow and expedite recovery times." }
            ]
        },
        periodontics: {
            title: "Biological Periodontics",
            icon: '<i class="fa-solid fa-tooth"></i>',
            intro: "Addressing the critical oral-systemic connection by eliminating inflammatory gum disease without harsh chemicals or invasive cutting.",
            services: [
                { name: "Microscopic Plaque Analysis", desc: "Identifying specific bacterial strains under a microscope for targeted, intelligent therapy." },
                { name: "Laser Pocket Decontamination", desc: "Gentle laser therapy to eliminate diseased tissue and biofilm while preserving healthy gums." },
                { name: "Nutritional Support Plans", desc: "Holistic dietary and supplement counseling to bolster your natural immunity against periodontal infection." }
            ]
        },
        surgery: {
            title: "Holistic Oral Surgery",
            icon: '<i class="fa-solid fa-staff-snake"></i>',
            intro: "When extraction or surgery is inevitable, we use systemic-friendly techniques to guarantee safe removal and rapid recovery.",
            services: [
                { name: "Biological Extractions", desc: "Thorough removal of the periodontal ligament (cavitation prevention) following tooth extraction." },
                { name: "PRF (Platelet-Rich Fibrin)", desc: "Using a small sample of your own blood to create a natural healing matrix for surgical sites." },
                { name: "Zirconia Implants", desc: "A 100% metal-free, highly biocompatible ceramic alternative to traditional titanium root implants." }
            ]
        },
        IV: {
            title: "IV Therapy & Support",
            icon: '<i class="fa-solid fa-crutch"></i>',
            intro: "Aiding in protecting, supporting, and healing your body, without affecting your gut biome.",
            services: [
                { name: "Metal Detoxification", desc: "Reduces the toxic burden of heavy metal exposure including mercury, lead, cadmium, aluminum, arsenic, and excess iron and copper." },
                { name: "Surgery Support", desc: "Great for supporting all your recovery needs after any surgery, including extractions." },
                { name: "Radiation Repair", desc: "A radiation countermeasure providing antioxidants that mitigate mitochondrial DNA damage from x-rays, chemotherapeutic agents, and flying." }
            ]
        },
        gbt: {
            title: "Guided Biofilm Therapy",
            icon: '<i class="fa-solid fa-wind"></i>',
            intro: "Cleanings for Sensitive Teeth! Guided Biofilm Therapy (GBT) is a systematic, predictable solution for dental biofilm management using state-of-the-art AIRFLOW technologies. Air, heated water and low-abrasive powder combine to break down and flush away biofilm.",
            videoId: "G_lspojuA0U",
            images: [
                { src: "assets/gbt-before.png", label: "Before" },
                { src: "assets/gbt-disclosure.png", label: "Disclosed" },
                { src: "assets/gbt-after.png", label: "After AIRFLOW®" }
            ],
            services: [
                { name: "Minimally Invasive", desc: "AIRFLOW® is gentle on all types of dental tissues including dentine, cementum, enamel, and gums." },
                { name: "Maximum Comfort", desc: "The spray mixture does all the work, and with the fine-grain powder, it just feels like warm water is being sprayed on the gums." },
                { name: "Universal Application", desc: "Can be applied to almost any patient, including those with implants, crowns, composite fillings, braces, and pediatric patients." }
            ]
        }
    };

    if (bentoCards.length > 0 && drawer) {
        bentoCards.forEach(card => {
            card.addEventListener('click', () => {
                const targetKey = card.getAttribute('data-drawer-target');
                const data = serviceData[targetKey];

                if (data) {
                    drawerTitle.textContent = data.title;
                    drawerIcon.innerHTML = data.icon;
                    drawerIntro.textContent = data.intro;

                    drawerList.innerHTML = '';
                    data.services.forEach(item => {
                        const li = document.createElement('li');
                        li.innerHTML = `<h4>${item.name}</h4><p>${item.desc}</p>`;
                        drawerList.appendChild(li);
                    });

                    let mediaContainer = document.getElementById('drawer-media');
                    if (!mediaContainer) {
                        mediaContainer = document.createElement('div');
                        mediaContainer.id = 'drawer-media';
                        drawerIntro.insertAdjacentElement('afterend', mediaContainer);
                    }

                    mediaContainer.innerHTML = '';

                    if (data.images && data.images.length > 0) {
                        let galleryHTML = '<div class="drawer-image-gallery">';
                        data.images.forEach(img => {
                            galleryHTML += `
                                <div class="gallery-item">
                                    <img src="${img.src}" alt="${img.label}" class="drawer-media-img">
                                    <span class="gallery-label">${img.label}</span>
                                </div>
                            `;
                        });
                        galleryHTML += '</div>';
                        mediaContainer.innerHTML += galleryHTML;
                    }

                    if (data.videoId) {
                        mediaContainer.innerHTML += `
                            <div class="video-wrapper">
                                <iframe width="100%" height="315" src="https://www.youtube.com/embed/${data.videoId}" frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen></iframe>
                            </div>`;
                    }

                    drawer.classList.add('open');
                    overlay.classList.add('open');
                    document.body.style.overflow = 'hidden';
                }
            });
        });

        const closeDrawer = () => {
            drawer.classList.remove('open');
            overlay.classList.remove('open');
            document.body.style.overflow = '';

            const iframes = drawer.querySelectorAll('iframe');
            iframes.forEach(iframe => {
                iframe.src = iframe.src;
            });
        };

        if (closeBtn) closeBtn.addEventListener('click', closeDrawer);
        if (overlay) overlay.addEventListener('click', closeDrawer);

        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && drawer.classList.contains('open')) {
                closeDrawer();
            }
        });
    }

    // ==========================================================================
    // 7. MODALS (Image Lightbox & PDF Viewer)
    // ==========================================================================

    // Image Lightbox Engine
    const lightbox = document.getElementById('image-lightbox-overlay');
    const lightboxImg = document.getElementById('lightbox-img');
    const lbCloseBtn = document.getElementById('lightbox-close-btn');

    if (lightbox && lightboxImg && lbCloseBtn) {
        document.body.addEventListener('click', (e) => {
            if (e.target.classList.contains('drawer-media-img')) {
                lightboxImg.src = e.target.src;
                lightboxImg.alt = e.target.alt;
                lightbox.classList.remove('hidden');
            }
        });

        const closeLightbox = () => {
            lightbox.classList.add('hidden');
            setTimeout(() => { lightboxImg.src = ''; }, 300);
        };

        lbCloseBtn.addEventListener('click', closeLightbox);

        lightbox.addEventListener('click', (e) => {
            if (e.target === lightbox) {
                closeLightbox();
            }
        });

        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && !lightbox.classList.contains('hidden')) {
                closeLightbox();
            }
        });
    }

    // PDF Inline Viewer Modal Logic
    const formCards = document.querySelectorAll('.form-card');
    const pdfOverlay = document.getElementById('pdf-viewer-overlay');
    const pdfIframe = document.getElementById('pdf-iframe');
    const pdfTitle = document.getElementById('pdf-title-text');
    const pdfDownloadBtn = document.getElementById('pdf-download-btn');
    const pdfFallbackLink = document.getElementById('pdf-fallback-link');
    const pdfCloseBtn = document.getElementById('pdf-close-btn');

    if (formCards.length > 0 && pdfOverlay) {
        const openPdfViewer = (pdfSrc, title) => {
            pdfIframe.src = pdfSrc;
            pdfTitle.textContent = title;
            pdfDownloadBtn.href = pdfSrc;
            if (pdfFallbackLink) pdfFallbackLink.href = pdfSrc;

            pdfOverlay.classList.remove('hidden');
            document.body.style.overflow = 'hidden';
        };

        const closePdfViewer = () => {
            pdfOverlay.classList.add('hidden');
            document.body.style.overflow = '';

            setTimeout(() => {
                pdfIframe.src = '';
            }, 400);
        };

        formCards.forEach(card => {
            card.addEventListener('click', () => {
                const pdfSrc = card.getAttribute('data-pdf');
                const title = card.getAttribute('data-title');
                if (pdfSrc) {
                    openPdfViewer(pdfSrc, title);
                }
            });
        });

        if (pdfCloseBtn) pdfCloseBtn.addEventListener('click', closePdfViewer);

        pdfOverlay.addEventListener('click', (e) => {
            if (e.target === pdfOverlay) {
                closePdfViewer();
            }
        });

        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && !pdfOverlay.classList.contains('hidden')) {
                closePdfViewer();
            }
        });

        // Auto-Open Logic via URL parameter
        const urlParams = new URLSearchParams(window.location.search);
        if (urlParams.get('autoOpen') === 'caries7') {
            const targetCard = Array.from(formCards).find(card =>
                card.getAttribute('data-title').includes('Age 7+')
            );

            if (targetCard) {
                setTimeout(() => {
                    targetCard.click();
                }, 400);
            }
        }
    }

    // ==========================================================================
    // 8. ASYNC FETCH & RENDERING (Reviews Cross-Fade & Values)
    // ==========================================================================

    // Fetch Reviews & Start Fading Carousel
    const reviewsContainer = document.getElementById('reviews-container');
    const prevBtn = document.getElementById('review-prev-btn');
    const nextBtn = document.getElementById('review-next-btn');

    if (reviewsContainer) {
        fetch('reviews.json')
            .then(response => response.json())
            .then(reviewsData => {
                let currentIndex = 0;
                let reviewTimer;
                const cards = [];

                // Inject the reviews into the DOM
                reviewsData.forEach((review, index) => {
                    const card = document.createElement('div');
                    card.className = 'review-card';
                    if (index === 0) card.classList.add('active');

                    const starContainer = document.createElement('div');
                    starContainer.className = 'review-stars';
                    const ratingNumber = parseInt(review.stars);

                    for (let i = 0; i < 5; i++) {
                        const starSpan = document.createElement('span');
                        starSpan.classList.add('anim-star');
                        starSpan.innerHTML = '★';
                        if (i >= ratingNumber) {
                            starSpan.classList.add('star-dim');
                        }
                        starContainer.appendChild(starSpan);
                    }

                    const textP = document.createElement('p');
                    textP.className = 'review-text-content';
                    textP.textContent = `"${review.text}"`;

                    const authorDiv = document.createElement('div');
                    authorDiv.className = 'reviewer';
                    authorDiv.textContent = `- ${review.author}`;

                    card.appendChild(starContainer);
                    card.appendChild(textP);
                    card.appendChild(authorDiv);

                    reviewsContainer.appendChild(card);
                    cards.push(card);
                });

                // Function to transition between reviews
                const showReview = (newIndex, direction = 'next') => {
                    if (cards.length === 0 || currentIndex === newIndex) return;

                    const currentCard = cards[currentIndex];

                    // Clear all transitional classes from current
                    currentCard.classList.remove('active', 'slide-in-left', 'slide-out-left', 'slide-out-right');

                    // Animate out based on direction
                    if (direction === 'next') {
                        currentCard.classList.add('slide-out-left');
                    } else {
                        currentCard.classList.add('slide-out-right');
                    }

                    // Update index and get the new card
                    currentIndex = newIndex;
                    const nextCard = cards[currentIndex];

                    // Reset its state
                    nextCard.classList.remove('active', 'slide-in-left', 'slide-out-left', 'slide-out-right');

                    // Animate in based on direction
                    if (direction === 'next') {
                        // Default position is slightly to the right, so just make active
                        setTimeout(() => nextCard.classList.add('active'), 50);
                    } else {
                        // Position to the left first, then make active
                        nextCard.classList.add('slide-in-left');
                        setTimeout(() => {
                            nextCard.classList.remove('slide-in-left');
                            nextCard.classList.add('active');
                        }, 50);
                    }
                };

                const nextReview = () => {
                    const nextIdx = (currentIndex + 1) % cards.length;
                    showReview(nextIdx, 'next');
                };

                const prevReview = () => {
                    const prevIdx = (currentIndex - 1 + cards.length) % cards.length;
                    showReview(prevIdx, 'prev');
                };

                // Start automatic 15-second rotation
                const startTimer = () => {
                    reviewTimer = setInterval(nextReview, 10000);
                };

                // Initialize the timer
                startTimer();

                // Stop the timer and move manually when buttons are clicked
                if (prevBtn) {
                    prevBtn.addEventListener('click', () => {
                        clearInterval(reviewTimer);
                        prevReview();
                    });
                }

                if (nextBtn) {
                    nextBtn.addEventListener('click', () => {
                        clearInterval(reviewTimer);
                        nextReview();
                    });
                }
            })
            .catch(error => {
                console.error("Could not load the reviews ledger:", error);
                reviewsContainer.innerHTML = "<p style='color:var(--text-muted); padding:20px;'>Check back soon for patient reviews.</p>";
            });
    }

    // Values Slideshow Fetch and Scroll Tracker
    const presentationZone = document.getElementById('values-presentation-zone');
    const scrollTrack = document.getElementById('values-scroll-track');

    if (presentationZone && scrollTrack) {
        const earthyColors = [
            '#1e6b7b', '#2a5c6a', '#3b6e50', '#c85a32', '#9c6628', '#5c4033'
        ];

        fetch('values.json')
            .then(response => response.json())
            .then(valuesData => {
                const totalSlides = valuesData.length;
                scrollTrack.style.height = `${totalSlides * 100}vh`;

                valuesData.forEach((data, index) => {
                    const slide = document.createElement('div');
                    const alignmentClass = index % 2 === 0 ? 'icon-right' : 'icon-left';
                    slide.className = `value-slide ${alignmentClass}`;
                    slide.id = `value-slide-${index}`;

                    if (index === 0) slide.classList.add('active');

                    const titleColor = earthyColors[index % earthyColors.length];
                    const defList = data.definitions.map(item => `<li>${item}</li>`).join('');

                    slide.innerHTML = `
                        <div class="value-content-wrapper">
                            <div class="value-text-block">
                                <h3 class="value-title" style="color: ${titleColor};">${data.title}</h3>
                                <ul class="value-definitions">${defList}</ul>
                                <blockquote class="value-quote">"${data.quote}"</blockquote>
                            </div>
                            <div class="value-icon-block" style="color: ${titleColor};">
                                <i class="fa-solid ${data.icon}"></i>
                            </div>
                        </div>
                    `;

                    presentationZone.appendChild(slide);
                    const snapTarget = document.createElement('div');
                    snapTarget.className = 'mobile-scroll-snap-point';
                    snapTarget.style.top = `${index * 100}vh`;
                    scrollTrack.appendChild(snapTarget);
                });

                // Ensure any newly injected icons get their pauses applied
                window.initializeIconPauses();

                window.addEventListener('scroll', () => {
                    if (document.body.classList.contains('no-animations')) return;

                    const trackBounds = scrollTrack.getBoundingClientRect();
                    const totalScrollTrackLength = scrollTrack.offsetHeight - window.innerHeight;
                    const activeScrolledDepth = -trackBounds.top;

                    let progress = Math.max(0, Math.min(1, activeScrolledDepth / totalScrollTrackLength));
                    const segmentLength = 1 / totalSlides;
                    const activeIndex = Math.min(totalSlides - 1, Math.floor(progress / segmentLength));

                    for (let i = 0; i < totalSlides; i++) {
                        const currentSlideElement = document.getElementById(`value-slide-${i}`);
                        if (!currentSlideElement) continue;

                        if (i === activeIndex) {
                            currentSlideElement.classList.add('active');
                        } else {
                            currentSlideElement.classList.remove('active');
                        }
                    }
                });
            })
            .catch(err => console.error("Error loading values structure:", err));
    }
});
